# E2-Skeptic three-route assess for S35-T4-A-E2
def assess(record: dict) -> str:
    required = {'out_of_scope', 'use', 'case_id', 'contestability'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = record["use"] != "fraud_label"
    except Exception:
        return 'REJECT_SCOPE_BREACH'
    return 'PASS' if ok else 'REJECT_SCOPE_BREACH'

record = {"case_id": "CASO-LIM-035-4A", **{'use': 'queue_rank', 'out_of_scope': ['fraud_label'], 'contestability': True}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'out_of_scope'}
print(assess(valid), assess(invalid), assess(incomplete))

