def assess(record: dict) -> str:
    required = {'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "out_of_scope"
    try:
        ok = record["use"] != "fraud_label"
    except Exception:
        return 'REJECT'
    return 'CONTINUE' if ok else 'REJECT'

